import{_ as e,c as a,o as r,d as o}from"./app.f23fced7.js";const f=JSON.parse('{"title":"项目部署","description":"","frontmatter":{},"headers":[{"level":2,"title":"Docker","slug":"docker","link":"#docker","children":[]}],"relativePath":"note/program/deploy.md","lastUpdated":1678787879000}'),d={name:"note/program/deploy.md"},i=o('<h1 id="项目部署" tabindex="-1">项目部署 <a class="header-anchor" href="#项目部署" aria-hidden="true">#</a></h1><h2 id="docker" tabindex="-1">Docker <a class="header-anchor" href="#docker" aria-hidden="true">#</a></h2><p>Docker就是打包提供软件运行环境的工具，可以将例如jvm,V8引擎(node),mysql8.0等等和软件一起打包，然后在任意容器中可以开箱即用，不需要再额外安装依赖环境。 Docker的三大概念：</p><ol><li>镜像文件：Dockerfile</li><li>镜像：Image</li><li>容器：Container</li></ol><h4 id="dockerfile" tabindex="-1">Dockerfile: <a class="header-anchor" href="#dockerfile" aria-hidden="true">#</a></h4><p>将操作系统,各种依赖与版本号写入Dockerfile,记录了程序运行时所需要的环境依赖。</p><h4 id="image" tabindex="-1">Image： <a class="header-anchor" href="#image" aria-hidden="true">#</a></h4><p>通过Dockerfile执行<code>docker build</code>指令来创建一个镜像，镜像是静态的，需要被解析才会生成真正的运行环境。</p><h4 id="container" tabindex="-1">Container: <a class="header-anchor" href="#container" aria-hidden="true">#</a></h4><p>指定image执行docker run命令，docker就为我们分配一个容器，将镜像转化为真正的运行环境，软件可在容器里面正常运行。</p>',10),c=[i];function t(n,l,h,s,_,p){return r(),a("div",null,c)}const m=e(d,[["render",t]]);export{f as __pageData,m as default};
